import{_ as n,o as i,c as t,ag as a}from"./chunks/framework.CxZWPeXl.js";const s=JSON.parse('{"title":"Câu hỏi thường gặp (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),c={name:"faq.md"};function o(g,h,u,l,r,p){return i(),t("div",null,[...h[0]||(h[0]=[a('<h1 id="cau-hoi-thuong-gap-faq" tabindex="-1">Câu hỏi thường gặp (FAQ) <a class="header-anchor" href="#cau-hoi-thuong-gap-faq" aria-label="Permalink to &quot;Câu hỏi thường gặp (FAQ)&quot;">​</a></h1><blockquote><p>Gặp vấn đề? Tìm câu trả lời tại đây</p></blockquote><h2 id="muc-luc" tabindex="-1">Mục lục <a class="header-anchor" href="#muc-luc" aria-label="Permalink to &quot;Mục lục&quot;">​</a></h2><ul><li><p>[Đăng nhập &amp; Tài khoản](#Đăng nhập &amp; Tài khoản)</p></li><li><p>[Luyện tập hội thoại](#Luyện tập hội thoại)</p></li><li><p>[Báo cáo đánh giá](#Báo cáo đánh giá)</p></li><li><p>[Lịch sử luyện tập](#Lịch sử luyện tập)</p></li><li><p>[Trợ lý kiến ​​thức](#Trợ lý kiến ​​thức)</p></li><li><p>[Chức năng quản trị viên](#Chức năng quản trị viên)</p></li><li><p>[Hệ thống &amp; Hiệu suất](#Hệ thống &amp; Hiệu suất)</p></li><li><p>[Tham khảo nhanh thông báo lỗi](#Tham khảo nhanh thông báo lỗi)</p></li></ul><hr><h2 id="đang-nhap-tai-khoan" tabindex="-1">Đăng nhập &amp; Tài khoản <a class="header-anchor" href="#đang-nhap-tai-khoan" aria-label="Permalink to &quot;Đăng nhập &amp; Tài khoản&quot;">​</a></h2><h3 id="hoi-toi-khong-the-đang-nhap-vao-he-thong" tabindex="-1">Hỏi: Tôi không thể đăng nhập vào hệ thống? <a class="header-anchor" href="#hoi-toi-khong-the-đang-nhap-vao-he-thong" aria-label="Permalink to &quot;Hỏi: Tôi không thể đăng nhập vào hệ thống?&quot;">​</a></h3><p><strong>Đáp:</strong> Vui lòng kiểm tra các mục sau theo thứ tự:</p><ol><li><p>Xác nhận bạn đang sử dụng tài khoản công ty (Google hoặc Microsoft), không phải tài khoản cá nhân.</p></li><li><p>Xác nhận tài khoản đã được quản trị viên thêm vào hệ thống.</p></li><li><p>Xác nhận trạng thái tài khoản là &quot;Có sẵn&quot; (không phải &quot;Đã vô hiệu hóa&quot;).</p></li><li><p>Thử xóa bộ nhớ cache của trình duyệt và đăng nhập lại.</p></li><li><p>Nếu sự cố vẫn tiếp diễn, hãy liên hệ với quản trị viên công ty của bạn.</p></li></ol><h3 id="hoi-sau-khi-đang-nhap-hien-thi-tai-khoan-đa-bi-vo-hieu-hoa" tabindex="-1">Hỏi: Sau khi đăng nhập, hiển thị &quot;Tài khoản đã bị vô hiệu hóa&quot;? <a class="header-anchor" href="#hoi-sau-khi-đang-nhap-hien-thi-tai-khoan-đa-bi-vo-hieu-hoa" aria-label="Permalink to &quot;Hỏi: Sau khi đăng nhập, hiển thị &quot;Tài khoản đã bị vô hiệu hóa&quot;?&quot;">​</a></h3><p><strong>Đáp:</strong> Tài khoản của bạn đã bị quản trị viên vô hiệu hóa. Vui lòng liên hệ với quản trị viên để thay đổi trạng thái tài khoản trở lại &quot;Có sẵn&quot;.</p><h3 id="hoi-sau-khi-đang-nhap-toi-khong-thay-mot-so-chuc-nang-chang-han-nhu-cai-đat-quan-ly-tro-ly-kien-​​thuc" tabindex="-1">Hỏi: Sau khi đăng nhập, tôi không thấy một số chức năng (chẳng hạn như cài đặt quản lý, trợ lý kiến ​​thức)? <a class="header-anchor" href="#hoi-sau-khi-đang-nhap-toi-khong-thay-mot-so-chuc-nang-chang-han-nhu-cai-đat-quan-ly-tro-ly-kien-​​thuc" aria-label="Permalink to &quot;Hỏi: Sau khi đăng nhập, tôi không thấy một số chức năng (chẳng hạn như cài đặt quản lý, trợ lý kiến ​​thức)?&quot;">​</a></h3><p><strong>Đáp:</strong> Khả năng hiển thị của các chức năng phụ thuộc vào cài đặt quyền của vai trò của bạn. Các vai trò khác nhau có quyền truy cập khác nhau vào các chức năng:</p><p>| Vai trò | Chức năng có sẵn |</p><p>| --- | --- |</p><p>| Người dùng | Thực hành đối thoại, Báo cáo đánh giá, Lịch sử thực hành, Bảng điều khiển |</p><p>| Quản trị viên | Các chức năng trên + Quản lý người dùng, Quản lý nhắc nhở, Quản lý giai đoạn, Quản lý cơ sở kiến ​​thức |</p><p>Để có thêm quyền, vui lòng liên hệ với quản trị viên để điều chỉnh cài đặt vai trò.</p><h3 id="hoi-lam-the-nao-đe-đang-xuat-khoi-he-thong" tabindex="-1">Hỏi: Làm thế nào để đăng xuất khỏi hệ thống? <a class="header-anchor" href="#hoi-lam-the-nao-đe-đang-xuat-khoi-he-thong" aria-label="Permalink to &quot;Hỏi: Làm thế nào để đăng xuất khỏi hệ thống?&quot;">​</a></h3><p><strong>Trả lời:</strong> Nhấp vào biểu tượng đăng xuất ở góc trên bên phải trang (mũi tên chỉ sang phải) và xác nhận &quot;Bạn có chắc chắn muốn đăng xuất không?&quot; để đăng xuất.</p><h3 id="hoi-lam-the-nao-đe-chuyen-đoi-ngon-ngu" tabindex="-1">Hỏi: Làm thế nào để chuyển đổi ngôn ngữ? <a class="header-anchor" href="#hoi-lam-the-nao-đe-chuyen-đoi-ngon-ngu" aria-label="Permalink to &quot;Hỏi: Làm thế nào để chuyển đổi ngôn ngữ?&quot;">​</a></h3><p><strong>Trả lời:</strong> Nhấp vào nút chuyển đổi ngôn ngữ ở góc trên bên phải trang và chọn ngôn ngữ bạn muốn (Tiếng Trung phồn thể / Tiếng Việt). Giao diện sẽ cập nhật ngay sau khi chuyển đổi.</p><hr><h2 id="luyen-tap-hoi-thoai" tabindex="-1">Luyện tập hội thoại <a class="header-anchor" href="#luyen-tap-hoi-thoai" aria-label="Permalink to &quot;Luyện tập hội thoại&quot;">​</a></h2><h3 id="hoi-su-khac-biet-giua-vai-tro-ngau-nhien-va-vai-tro-tuy-chinh-la-gi" tabindex="-1">Hỏi: Sự khác biệt giữa &quot;Vai trò ngẫu nhiên&quot; và &quot;Vai trò tùy chỉnh&quot; là gì? <a class="header-anchor" href="#hoi-su-khac-biet-giua-vai-tro-ngau-nhien-va-vai-tro-tuy-chinh-la-gi" aria-label="Permalink to &quot;Hỏi: Sự khác biệt giữa &quot;Vai trò ngẫu nhiên&quot; và &quot;Vai trò tùy chỉnh&quot; là gì?&quot;">​</a></h3><p><strong>Trả lời:</strong></p><p>| Chế độ | Mô tả |</p><p>| --- | --- |</p><p>| Vai trò ngẫu nhiên | Hệ thống tạo ra các vai trò khách hàng hoàn toàn ngẫu nhiên (tuổi, nghề nghiệp, giới tính, thu nhập, v.v. đều được chọn ngẫu nhiên), phù hợp để luyện tập nhanh. |</p><p>| Vai trò tùy chỉnh | Bạn có thể chỉ định một số hoặc tất cả các thuộc tính của khách hàng (ví dụ: đặt &quot;thu nhập cao, đã kết hôn&quot;). Các thuộc tính không được chỉ định sẽ được hệ thống điền ngẫu nhiên.</p><h3 id="hoi-toi-co-phai-đien-tat-ca-cac-truong-khi-tao-vai-tro-tuy-chinh-khong" tabindex="-1">Hỏi: Tôi có phải điền tất cả các trường khi tạo vai trò tùy chỉnh không? <a class="header-anchor" href="#hoi-toi-co-phai-đien-tat-ca-cac-truong-khi-tao-vai-tro-tuy-chinh-khong" aria-label="Permalink to &quot;Hỏi: Tôi có phải điền tất cả các trường khi tạo vai trò tùy chỉnh không?&quot;">​</a></h3><p><strong>Đáp:</strong> Không. Tất cả các trường đều là tùy chọn. Bạn chỉ cần thiết lập các thuộc tính mà bạn quan tâm, và AI sẽ tự động điền phần còn lại. Ví dụ, nếu bạn chỉ thiết lập &quot;35 tuổi, đã kết hôn, thu nhập cao&quot;, hệ thống sẽ tự động tạo ra các thuộc tính khác.</p><h3 id="hoi-loai-tinh-cach-mbti-co-anh-huong-đen-hanh-vi-cua-khach-hang-ai-khong" tabindex="-1">Hỏi: Loại tính cách MBTI có ảnh hưởng đến hành vi của khách hàng AI không? <a class="header-anchor" href="#hoi-loai-tinh-cach-mbti-co-anh-huong-đen-hanh-vi-cua-khach-hang-ai-khong" aria-label="Permalink to &quot;Hỏi: Loại tính cách MBTI có ảnh hưởng đến hành vi của khách hàng AI không?&quot;">​</a></h3><p><strong>Đáp:</strong> Có. Loại MBTI ảnh hưởng đáng kể đến phong cách giao tiếp, quá trình ra quyết định và mô hình phản ứng của khách hàng AI. Ví dụ:</p><ul><li><p>**Khách hàng thuộc loại ISTJ (Chuyên gia hậu cần) coi trọng dữ liệu và chi tiết hơn.</p></li><li><p>**Khách hàng thuộc loại ENFP (Kỹ sư) tập trung nhiều hơn vào kết nối cảm xúc.</p></li><li><p>**Khách hàng thuộc loại INTJ (Kiến trúc sư) đi thẳng vào vấn đề.</p></li></ul><p>Bạn có thể nhấp vào chú thích bên cạnh phần &quot;Tính cách&quot; trong bảng thiết lập vai trò để xem mô tả chi tiết của từng loại.</p><h3 id="hoi-tai-sao-viec-tao-vai-tro-lai-mat-nhieu-thoi-gian-nhu-vay" tabindex="-1">Hỏi: Tại sao việc tạo vai trò lại mất nhiều thời gian như vậy? <a class="header-anchor" href="#hoi-tai-sao-viec-tao-vai-tro-lai-mat-nhieu-thoi-gian-nhu-vay" aria-label="Permalink to &quot;Hỏi: Tại sao việc tạo vai trò lại mất nhiều thời gian như vậy?&quot;">​</a></h3><p><strong>Đáp:</strong> Việc tạo vai trò thường chỉ mất vài giây. Nếu mất hơn 30 giây, có thể là do sự cố mạng. Vui lòng thử làm mới trang và thử lại.</p><h3 id="hoi-tai-sao-phan-hoi-cua-may-khach-ai-trong-cuoc-hoi-thoai-lai-khong-hop-ly" tabindex="-1">Hỏi: Tại sao phản hồi của máy khách AI trong cuộc hội thoại lại không hợp lý? <a class="header-anchor" href="#hoi-tai-sao-phan-hoi-cua-may-khach-ai-trong-cuoc-hoi-thoai-lai-khong-hop-ly" aria-label="Permalink to &quot;Hỏi: Tại sao phản hồi của máy khách AI trong cuộc hội thoại lại không hợp lý?&quot;">​</a></h3><p><strong>Đáp:</strong> Các lý do và gợi ý có thể:</p><ol><li><p><strong>Thiết lập vai trò quá cực đoan</strong> — Hãy thử sử dụng sự kết hợp thuộc tính hợp lý hơn.</p></li><li><p><strong>Cuộc hội thoại không rõ ràng</strong> — Hãy thử giao tiếp bằng những biểu đạt rõ ràng hơn.</p></li><li><p><strong>Cần điều chỉnh lời nhắc</strong> — Hãy báo cáo cho quản trị viên và yêu cầu họ xem xét và điều chỉnh cài đặt Lời nhắc của AI.</p></li></ol><h3 id="hoi-khong-the-gui-tin-nhan-va-hien-thi-canh-bao-bao-mat" tabindex="-1">Hỏi: Không thể gửi tin nhắn và hiển thị cảnh báo bảo mật? <a class="header-anchor" href="#hoi-khong-the-gui-tin-nhan-va-hien-thi-canh-bao-bao-mat" aria-label="Permalink to &quot;Hỏi: Không thể gửi tin nhắn và hiển thị cảnh báo bảo mật?&quot;">​</a></h3><p><strong>Đáp:</strong> Hệ thống có cơ chế phát hiện bảo mật nội dung được tích hợp sẵn. Các tin nhắn chứa nội dung sau sẽ bị chặn:</p><ul><li><p>Thông tin cá nhân (số điện thoại, địa chỉ, số CMND, v.v.)</p></li><li><p>Nội dung cố gắng vượt qua các hạn chế bảo mật hệ thống</p></li><li><p>Nội dung không phù hợp hoặc có rủi ro cao</p></li><li><p>Liên kết độc hại</p></li></ul><p>Vui lòng chỉnh sửa nội dung tin nhắn và gửi lại. Việc kiểm tra này nhằm đảm bảo an ninh cho môi trường thực hành.</p><h3 id="hoi-toi-co-the-tiep-tuc-phien-thuc-hanh-neu-dung-giua-chung-khong" tabindex="-1">Hỏi: Tôi có thể tiếp tục phiên thực hành nếu dừng giữa chừng không? <a class="header-anchor" href="#hoi-toi-co-the-tiep-tuc-phien-thuc-hanh-neu-dung-giua-chung-khong" aria-label="Permalink to &quot;Hỏi: Tôi có thể tiếp tục phiên thực hành nếu dừng giữa chừng không?&quot;">​</a></h3><p><strong>Trả lời:</strong> Có. Các phiên thực hành chưa hoàn thành có thể được tiếp tục theo các cách sau:</p><ul><li><p>Nút &quot;Tiếp tục thực hành&quot; trong các bản ghi gần đây trên bảng điều khiển</p></li><li><p>Nút &quot;Tiếp tục thực hành&quot; trong lịch sử thực hành</p></li></ul><p>Khi tiếp tục thực hành, máy khách AI sẽ nhớ mang máng về cuộc trò chuyện trước đó.</p><h3 id="hoi-toi-co-the-thuc-hanh-lai-voi-cung-mot-may-khach-khong" tabindex="-1">Hỏi: Tôi có thể thực hành lại với cùng một máy khách không? <a class="header-anchor" href="#hoi-toi-co-the-thuc-hanh-lai-voi-cung-mot-may-khach-khong" aria-label="Permalink to &quot;Hỏi: Tôi có thể thực hành lại với cùng một máy khách không?&quot;">​</a></h3><p><strong>Trả lời:</strong> Có. Nhấp vào &quot;Thử thách lại&quot; trong bảng điều khiển hoặc lịch sử thực hành để bắt đầu một cuộc trò chuyện mới bằng cách sử dụng cùng cài đặt vai trò máy khách. Điều này rất hữu ích để so sánh hiệu quả của các chiến lược khác nhau. ... ### Hỏi: Khi nào tôi nên kết thúc cuộc trò chuyện?</p><p><strong>Đáp:</strong> Chúng tôi khuyên bạn nên kết thúc phiên trong các trường hợp sau:</p><ol><li><p>Bạn đã hoàn thành các mục tiêu thực hành đã được xác định trước.</p></li><li><p>Máy khách AI bày tỏ mong muốn kết thúc cuộc trò chuyện (một thông báo sẽ hiện lên).</p></li><li><p>Bạn cảm thấy mình đã đạt được các mục tiêu học tập.</p></li><li><p>Bạn muốn xem kết quả đánh giá hiện tại.</p></li></ol><hr><h2 id="bao-cao-đanh-gia" tabindex="-1">Báo cáo đánh giá <a class="header-anchor" href="#bao-cao-đanh-gia" aria-label="Permalink to &quot;Báo cáo đánh giá&quot;">​</a></h2><h3 id="hoi-bao-cao-đanh-gia-bi-ket-o-trang-thai-đang-tao" tabindex="-1">Hỏi: Báo cáo đánh giá bị kẹt ở trạng thái &quot;Đang tạo&quot;? <a class="header-anchor" href="#hoi-bao-cao-đanh-gia-bi-ket-o-trang-thai-đang-tao" aria-label="Permalink to &quot;Hỏi: Báo cáo đánh giá bị kẹt ở trạng thái &quot;Đang tạo&quot;?&quot;">​</a></h3><p><strong>Đáp:</strong> Việc tạo báo cáo thường mất từ ​​30 giây đến 2 phút. Nếu sau 5 phút mà vẫn chưa hoàn tất:</p><ol><li><p>Thử xem lại trang.</p></li><li><p>Chờ một chút và kiểm tra lại.</p></li><li><p>Nếu vấn đề vẫn tiếp diễn, hãy liên hệ với quản trị viên.</p></li></ol><p>Mỗi phần của báo cáo (đánh giá theo giai đoạn, đánh giá toàn diện, v.v.) được tạo độc lập; một số phần có thể hoàn thành trước.</p><h3 id="hoi-su-khac-biet-giua-đanh-gia-toan-dien-va-đanh-gia-tung-cau-la-gi" tabindex="-1">Hỏi: Sự khác biệt giữa &quot;Đánh giá toàn diện&quot; và &quot;Đánh giá từng câu&quot; là gì? <a class="header-anchor" href="#hoi-su-khac-biet-giua-đanh-gia-toan-dien-va-đanh-gia-tung-cau-la-gi" aria-label="Permalink to &quot;Hỏi: Sự khác biệt giữa &quot;Đánh giá toàn diện&quot; và &quot;Đánh giá từng câu&quot; là gì?&quot;">​</a></h3><p><strong>Đáp:</strong></p><p>| Chế độ | Mô tả |</p><p>| --- | --- |</p><p>| Đánh giá toàn diện | Phân tích tổng thể, bao gồm trạng thái hoàn thành từng giai đoạn, đánh giá hiệu suất tổng thể, đề xuất cải thiện, v.v. |</p><p>| Đánh giá từng câu | Phân tích từng dòng trong mỗi vòng hội thoại (tin nhắn của bạn + phản hồi của AI), cung cấp phản hồi cụ thể về kỹ năng diễn đạt |</p><p>Nên xem &quot;Đánh giá toàn diện&quot; trước để hiểu hiệu suất tổng thể, sau đó chuyển sang &quot;Đánh giá từng câu&quot; để tìm ra các chi tiết hội thoại cụ thể cần cải thiện.</p><h3 id="hoi-suy-nghi-noi-tam-cua-ai-la-gi" tabindex="-1">Hỏi: &quot;Suy nghĩ nội tâm của AI&quot; là gì? <a class="header-anchor" href="#hoi-suy-nghi-noi-tam-cua-ai-la-gi" aria-label="Permalink to &quot;Hỏi: &quot;Suy nghĩ nội tâm của AI&quot; là gì?&quot;">​</a></h3><p><strong>Đáp:</strong> Suy nghĩ nội tâm của AI hiển thị mô phỏng của AI về các hoạt động tâm lý của khách hàng sau khi nhận được tin nhắn của bạn. Điều này giúp bạn hiểu được suy nghĩ thực sự của khách hàng tại mỗi thời điểm, giúp bạn điều chỉnh chiến lược giao tiếp lần sau.</p><h3 id="hoi-toi-khong-hai-long-voi-ket-qua-đanh-gia-toi-co-the-cung-cap-phan-hoi-khong" tabindex="-1">Hỏi: Tôi không hài lòng với kết quả đánh giá, tôi có thể cung cấp phản hồi không? <a class="header-anchor" href="#hoi-toi-khong-hai-long-voi-ket-qua-đanh-gia-toi-co-the-cung-cap-phan-hoi-khong" aria-label="Permalink to &quot;Hỏi: Tôi không hài lòng với kết quả đánh giá, tôi có thể cung cấp phản hồi không?&quot;">​</a></h3><p><strong>Đáp:</strong> Có. Mỗi phần đánh giá đều có chức năng xếp hạng bên dưới:</p><ul><li><p><strong>Tích cực</strong> — Bạn thấy đánh giá hữu ích (bạn có thể thêm nhận xét)</p></li><li><p><strong>Trung lập</strong> — Mặc định, không có nhận xét đặc biệt</p></li><li><p><strong>Tiêu cực</strong> — Bạn cảm thấy đánh giá cần được cải thiện (vui lòng giải thích lý do)</p></li></ul><p>Phản hồi của bạn sẽ giúp hệ thống liên tục tối ưu hóa chất lượng đánh giá.</p><h3 id="hoi-tai-sao-lai-hien-thi-khong-đat-đuoc-giai-đoan-đanh-gia" tabindex="-1">Hỏi: Tại sao lại hiển thị &quot;Không đạt được giai đoạn đánh giá&quot;? <a class="header-anchor" href="#hoi-tai-sao-lai-hien-thi-khong-đat-đuoc-giai-đoan-đanh-gia" aria-label="Permalink to &quot;Hỏi: Tại sao lại hiển thị &quot;Không đạt được giai đoạn đánh giá&quot;?&quot;">​</a></h3><p><strong>Đáp:</strong> Điều này có nghĩa là trong bài tập này, AI ​​đánh giá rằng cuộc trò chuyện của bạn không đáp ứng các tiêu chuẩn của giai đoạn bán hàng đầu tiên. Các lý do có thể:</p><ul><li><p>Quá ít vòng trò chuyện</p></li><li><p>Thiếu hành vi phá vỡ sự ngại ngùng/xây dựng lòng tin</p></li><li><p>Cuộc trò chuyện lạc đề khỏi chủ đề bán hàng</p></li></ul><p>Bạn nên xem lại phản hồi cụ thể trong phần đánh giá từng câu để hiểu rõ hướng cần cải thiện.</p><hr><h2 id="lich-su-bai-tap" tabindex="-1">Lịch sử bài tập <a class="header-anchor" href="#lich-su-bai-tap" aria-label="Permalink to &quot;Lịch sử bài tập&quot;">​</a></h2><h3 id="hoi-khong-tim-thay-ban-ghi-sau-khi-loc" tabindex="-1">Hỏi: Không tìm thấy bản ghi sau khi lọc? <a class="header-anchor" href="#hoi-khong-tim-thay-ban-ghi-sau-khi-loc" aria-label="Permalink to &quot;Hỏi: Không tìm thấy bản ghi sau khi lọc?&quot;">​</a></h3><p><strong>A:</strong> Vui lòng lưu ý những điều sau:</p><ol><li><p>Xác nhận phạm vi ngày đã được thiết lập chính xác.</p></li><li><p>Thử giảm phạm vi tiêu chí lọc.</p></li><li><p>Nhấp vào &quot;Xóa tất cả&quot; để xóa tất cả các bộ lọc và kiểm tra xem còn bản ghi nào không.</p></li><li><p>Xác nhận rằng các điều kiện trong cột nhãn bộ lọc đáp ứng mong đợi.</p></li></ol><p>Nếu không tìm thấy bản ghi nào, điều đó có nghĩa là không có hoạt động nào được thực hiện theo các điều kiện đó.</p><h3 id="hoi-tai-sao-toi-khong-the-nhap-vao-nut-tiep-tuc-thuc-hanh" tabindex="-1">Hỏi: Tại sao tôi không thể nhấp vào nút &quot;Tiếp tục thực hành&quot;? <a class="header-anchor" href="#hoi-tai-sao-toi-khong-the-nhap-vao-nut-tiep-tuc-thuc-hanh" aria-label="Permalink to &quot;Hỏi: Tại sao tôi không thể nhấp vào nút &quot;Tiếp tục thực hành&quot;?&quot;">​</a></h3><p><strong>A:</strong> Chỉ những hoạt động có trạng thái &quot;Đang tiến hành&quot; mới có thể tiếp tục. Nếu một hoạt động đã kết thúc (thủ công hoặc tự động bởi hệ thống), bạn chỉ có thể sử dụng &quot;Thử thách lại&quot; để bắt đầu một cuộc trò chuyện mới.</p><hr><h2 id="tro-ly-kien-thuc" tabindex="-1">Trợ lý Kiến thức <a class="header-anchor" href="#tro-ly-kien-thuc" aria-label="Permalink to &quot;Trợ lý Kiến thức&quot;">​</a></h2><h3 id="hoi-cau-tra-loi-cua-tro-ly-kien-thuc-co-khong-chinh-xac-hoac-khong-đay-đu-khong" tabindex="-1">Hỏi: Câu trả lời của Trợ lý Kiến thức có không chính xác hoặc không đầy đủ không? <a class="header-anchor" href="#hoi-cau-tra-loi-cua-tro-ly-kien-thuc-co-khong-chinh-xac-hoac-khong-đay-đu-khong" aria-label="Permalink to &quot;Hỏi: Câu trả lời của Trợ lý Kiến thức có không chính xác hoặc không đầy đủ không?&quot;">​</a></h3><p><strong>A:</strong> Chất lượng câu trả lời của Trợ lý Kiến thức phụ thuộc vào các yếu tố sau:</p><ol><li><p><strong>Nội dung Cơ sở Kiến thức</strong> — Câu trả lời dựa trên các tệp do quản trị viên tải lên. 1. Nếu cơ sở kiến ​​thức thiếu thông tin liên quan, câu trả lời có thể không đủ chính xác.</p></li><li><p><strong>Mô tả vấn đề</strong> — Hãy thử mô tả vấn đề theo nhiều cách khác nhau; điều này có thể mang lại kết quả tốt hơn.</p></li><li><p><strong>Tính cập nhật của nội dung</strong> — Nếu thông tin đã lỗi thời, vui lòng liên hệ với quản trị viên để cập nhật cơ sở kiến ​​thức.</p></li></ol><blockquote><p>Câu trả lời của Trợ lý Kiến thức chỉ mang tính tham khảo. Vui lòng tham khảo tài liệu chính thức của công ty để biết cách vận hành thực tế.</p></blockquote><h3 id="hoi-khong-thay-bieu-tuong-tro-ly-kien-thuc" tabindex="-1">Hỏi: Không thấy biểu tượng Trợ lý Kiến thức? <a class="header-anchor" href="#hoi-khong-thay-bieu-tuong-tro-ly-kien-thuc" aria-label="Permalink to &quot;Hỏi: Không thấy biểu tượng Trợ lý Kiến thức?&quot;">​</a></h3><p><strong>A:</strong> Tài khoản của bạn có thể không có quyền đọc cơ sở kiến ​​thức. Vui lòng liên hệ với quản trị viên để xác nhận cài đặt quyền.</p><h3 id="hoi-lich-su-hoi-thoai-bien-mat" tabindex="-1">Hỏi: Lịch sử hội thoại biến mất? <a class="header-anchor" href="#hoi-lich-su-hoi-thoai-bien-mat" aria-label="Permalink to &quot;Hỏi: Lịch sử hội thoại biến mất?&quot;">​</a></h3><p><strong>A:</strong> Lịch sử hội thoại của Trợ lý Kiến thức được lưu trữ trong trình duyệt cục bộ của bạn. Các thao tác sau sẽ khiến lịch sử biến mất:</p><ul><li><p>Xóa dữ liệu/bộ nhớ cache của trình duyệt</p></li><li><p>Nhấp vào nút &quot;Xóa trò chuyện&quot;</p></li><li><p>Sử dụng chế độ duyệt web riêng tư</p></li><li><p>Thay đổi trình duyệt hoặc thiết bị</p></li></ul><hr><h2 id="chuc-nang-quan-tri-vien" tabindex="-1">Chức năng quản trị viên <a class="header-anchor" href="#chuc-nang-quan-tri-vien" aria-label="Permalink to &quot;Chức năng quản trị viên&quot;">​</a></h2><h3 id="hoi-nhap-hang-loat-nguoi-dung-that-bai" tabindex="-1">Hỏi: Nhập hàng loạt người dùng thất bại? <a class="header-anchor" href="#hoi-nhap-hang-loat-nguoi-dung-that-bai" aria-label="Permalink to &quot;Hỏi: Nhập hàng loạt người dùng thất bại?&quot;">​</a></h3><p><strong>Đáp:</strong> Nguyên nhân thường gặp:</p><p>| Nguyên nhân | Giải pháp |</p><p>| --- | --- |</p><p>| Tệp không ở định dạng CSV | Xác nhận đã lưu ở định dạng .csv |</p><p>| Thứ tự trường CSV không chính xác | Tải xuống mẫu và điền theo định dạng mẫu |</p><p>| Email trùng lặp | Xác nhận không có email trùng lặp |</p><p>| Thiếu các trường bắt buộc | Xác nhận tất cả dữ liệu trong mỗi cột đã đầy đủ |</p><p>| Mã công ty/phòng ban không tồn tại | Xác nhận đang sử dụng mã công ty và phòng ban chính xác |</p><p>Hệ thống sẽ cung cấp báo cáo lỗi chi tiết, bao gồm số dòng và lý do cụ thể cho mỗi mục nhập không thành công.</p><h3 id="hoi-khi-nao-cac-thay-đoi-đoi-voi-loi-nhac-se-co-hieu-luc" tabindex="-1">Hỏi: Khi nào các thay đổi đối với lời nhắc sẽ có hiệu lực? <a class="header-anchor" href="#hoi-khi-nao-cac-thay-đoi-đoi-voi-loi-nhac-se-co-hieu-luc" aria-label="Permalink to &quot;Hỏi: Khi nào các thay đổi đối với lời nhắc sẽ có hiệu lực?&quot;">​</a></h3><p><strong>A:</strong> Sau khi chỉnh sửa Lời nhắc, bạn cần &quot;xuất bản&quot; (kích hoạt) phiên bản để nó có hiệu lực. Sau khi có hiệu lực:</p><ul><li><p><strong>Các cuộc hội thoại mới</strong> — Sử dụng Lời nhắc mới ngay lập tức</p></li><li><p><strong>Các cuộc hội thoại đang diễn ra</strong> — Không bị ảnh hưởng, tiếp tục sử dụng phiên bản gốc</p></li></ul><h3 id="q-viec-xoa-mot-giai-đoan-co-anh-huong-đen-cac-bai-tap-đa-hoan-thanh-khong" tabindex="-1">Q: Việc xóa một giai đoạn có ảnh hưởng đến các bài tập đã hoàn thành không? <a class="header-anchor" href="#q-viec-xoa-mot-giai-đoan-co-anh-huong-đen-cac-bai-tap-đa-hoan-thanh-khong" aria-label="Permalink to &quot;Q: Việc xóa một giai đoạn có ảnh hưởng đến các bài tập đã hoàn thành không?&quot;">​</a></h3><p><strong>A:</strong> Việc xóa một giai đoạn sẽ không ảnh hưởng đến dữ liệu thực hành đã hoàn thành, nhưng có thể ảnh hưởng đến việc hiển thị của nó trong báo cáo đánh giá. Bạn nên xác nhận rằng không có bài thực hành nào đang sử dụng giai đoạn này trước khi xóa.</p><h3 id="q-lam-the-nao-đe-khoi-phuc-nguoi-dung-đa-xoa" tabindex="-1">Q: Làm thế nào để khôi phục người dùng đã xóa? <a class="header-anchor" href="#q-lam-the-nao-đe-khoi-phuc-nguoi-dung-đa-xoa" aria-label="Permalink to &quot;Q: Làm thế nào để khôi phục người dùng đã xóa?&quot;">​</a></h3><p><strong>A:</strong> Hệ thống sử dụng cơ chế xóa mềm. Dữ liệu người dùng đã xóa vẫn được lưu giữ trong cơ sở dữ liệu. Để khôi phục, vui lòng liên hệ với quản trị viên hệ thống hoặc nhóm kỹ thuật.</p><hr><h2 id="he-thong-va-hieu-suat" tabindex="-1">Hệ thống và Hiệu suất <a class="header-anchor" href="#he-thong-va-hieu-suat" aria-label="Permalink to &quot;Hệ thống và Hiệu suất&quot;">​</a></h2><h3 id="q-he-thong-tai-cham" tabindex="-1">Q: Hệ thống tải chậm? <a class="header-anchor" href="#q-he-thong-tai-cham" aria-label="Permalink to &quot;Q: Hệ thống tải chậm?&quot;">​</a></h3><p><strong>A:</strong> Chúng tôi khuyên bạn nên kiểm tra những điều sau:</p><ol><li><p>Kết nối mạng của bạn có ổn định không?</p></li><li><p>Bạn có đang sử dụng phiên bản mới nhất của trình duyệt được hỗ trợ không?</p></li><li><p>Thử đóng các tab khác đang tiêu tốn nhiều tài nguyên.</p></li><li><p>Xóa bộ nhớ cache của trình duyệt và thử lại.</p></li></ol><h3 id="hoi-đa-xay-ra-loi-may-chu-vui-long-thu-lai-sau" tabindex="-1">Hỏi: &quot;Đã xảy ra lỗi máy chủ, vui lòng thử lại sau&quot;? <a class="header-anchor" href="#hoi-đa-xay-ra-loi-may-chu-vui-long-thu-lai-sau" aria-label="Permalink to &quot;Hỏi: &quot;Đã xảy ra lỗi máy chủ, vui lòng thử lại sau&quot;?&quot;">​</a></h3><p><strong>Đáp:</strong> Điều này cho thấy sự cố tạm thời của dịch vụ máy chủ. Khuyến nghị:</p><ol><li><p>Chờ vài phút và thử lại.</p></li><li><p>Nếu sự cố vẫn tiếp diễn sau hơn 30 phút, hãy liên hệ với quản trị viên hoặc bộ phận CNTT.</p></li><li><p>Không nên thử lại nhiều lần để tránh làm tăng tải cho máy chủ.</p></li></ol><h3 id="hoi-he-thong-ho-tro-nhung-trinh-duyet-nao" tabindex="-1">Hỏi: Hệ thống hỗ trợ những trình duyệt nào? <a class="header-anchor" href="#hoi-he-thong-ho-tro-nhung-trinh-duyet-nao" aria-label="Permalink to &quot;Hỏi: Hệ thống hỗ trợ những trình duyệt nào?&quot;">​</a></h3><p><strong>Đáp:</strong></p><p>| Trình duyệt | Phiên bản được hỗ trợ |</p><p>| --- | --- |</p><p>| Google Chrome | Phiên bản mới nhất |</p><p>| Microsoft Edge | Phiên bản mới nhất |</p><p>| Mozilla Firefox | Phiên bản mới nhất |</p><p>| Apple Safari | Phiên bản mới nhất |</p><p>Chúng tôi khuyên bạn nên sử dụng Chrome hoặc Edge để có trải nghiệm tốt nhất.</p><hr><h2 id="tham-khao-nhanh-cac-thong-bao-loi" tabindex="-1">Tham khảo nhanh các thông báo lỗi <a class="header-anchor" href="#tham-khao-nhanh-cac-thong-bao-loi" aria-label="Permalink to &quot;Tham khảo nhanh các thông báo lỗi&quot;">​</a></h2><p>| Thông báo lỗi | Mô tả | Phương pháp xử lý |</p><p>| --- | --- | --- |</p><p>| Xác thực không thành công, vui lòng đăng nhập lại và thử lại | Trạng thái đăng nhập đã hết hạn | Đăng nhập lại |</p><p>| Truy cập không mong muốn, vui lòng thử lại sau hoặc liên hệ quản trị viên | Không đủ quyền | Xác nhận quyền tài khoản, liên hệ quản trị viên |</p><p>| Yêu cầu quá thường xuyên, vui lòng thử lại sau | Tần suất thao tác vượt quá giới hạn | Chờ vài phút và thử lại |</p><p>| Lỗi máy chủ, vui lòng thử lại sau | Ngoại lệ dịch vụ phụ trợ | Chờ và thử lại hoặc liên hệ bộ phận CNTT |</p><p>| Lỗi kết nối mạng | Gián đoạn mạng | Kiểm tra kết nối mạng |</p><p>| Không tìm thấy tài nguyên | Tài nguyên được yêu cầu không tồn tại | Xác nhận mục tiêu thao tác là chính xác |</p><p>| Thao tác thất bại | Ngoại lệ thao tác chung | Thử lại hoặc liên hệ quản trị viên |</p><p>| Dữ liệu đầu vào không chính xác | Xác thực biểu mẫu không thành công | Kiểm tra xem nội dung đầu vào có đáp ứng yêu cầu định dạng không |</p><p>| Chứa ký tự không an toàn | Bảo vệ XSS được kích hoạt | Xóa các ký tự đặc biệt và thử lại |</p><hr><h2 id="van-con-cau-hoi" tabindex="-1">Vẫn còn câu hỏi? <a class="header-anchor" href="#van-con-cau-hoi" aria-label="Permalink to &quot;Vẫn còn câu hỏi?&quot;">​</a></h2><p>Nếu các câu hỏi thường gặp ở trên không giải quyết được vấn đề của bạn:</p><ol><li><p>Liên hệ với quản trị viên hệ thống của công ty bạn.</p></li><li><p>Gửi yêu cầu hỗ trợ đến bộ phận CNTT.</p></li><li><p>Cung cấp các thông tin sau để đẩy nhanh quá trình khắc phục sự cố:</p></li></ol><ul><li><p>Địa chỉ email tài khoản của bạn</p></li><li><p>Thời điểm xảy ra sự cố</p></li><li><p>Mô tả chi tiết về sự cố</p></li><li><p>Ảnh chụp màn hình (nếu có)</p></li><li><p>Toàn bộ thông báo lỗi</p></li></ul>',149)])])}const k=n(c,[["render",o]]);export{s as __pageData,k as default};
